code.JavaScript:
function searchInsertPosition(arr, n, k) {
    let left = 0;
    let right = n - 1;

    while (left <= right) {
        let middle = Math.floor((left + right) / 2);

        if (arr[middle] === k) {
            return middle;
        } else if (arr[middle] > k) {
            right = middle - 1;
        } else {
            left = middle + 1;
        }
    }

    return left;
}
